import{_ as t,c as l,o as i,a1 as e}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"FAQ 및 최적화: 문제 해결, CLI 명령, 성능 튜닝 | Clawdbot 튜토리얼","description":"Clawdbot 사용 시 일반적인 문제를 해결하고, 완전한 CLI 명령 참조를 마스터하며, 성능 최적화 기술을 배워 시스템 안정성과 응답 속도를 향상시킵니다.","frontmatter":{"title":"FAQ 및 최적화: 문제 해결, CLI 명령, 성능 튜닝 | Clawdbot 튜토리얼","sidebarTitle":"문제가 발생하면","subtitle":"FAQ 및 최적화","description":"Clawdbot 사용 시 일반적인 문제를 해결하고, 완전한 CLI 명령 참조를 마스터하며, 성능 최적화 기술을 배워 시스템 안정성과 응답 속도를 향상시킵니다.","tags":["FAQ","문제 해결","CLI","성능 최적화"],"order":300},"headers":[],"relativePath":"ko/moltbot/moltbot/faq/index.md","filePath":"ko/moltbot/moltbot/faq/index.md"}'),o={name:"ko/moltbot/moltbot/faq/index.md"};function r(n,a,s,d,h,p){return i(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="faq-및-최적화" tabindex="-1">FAQ 및 최적화 <a class="header-anchor" href="#faq-및-최적화" aria-label="Permalink to &quot;FAQ 및 최적화&quot;">​</a></h1><p>이 장절은 Clawdbot 사용 시 발생하는 다양한 문제를 해결하고, 완전한 명령줄 작업 방법을 마스터하며, 시스템 성능을 최적화하는 방법을 배우는 데 도움을 줍니다.</p><div class="info custom-block"><p class="custom-block-title">학습 순서 권장</p><p>이 장절의 내용을 다음 순서로 읽는 것을 권장합니다:</p><ol><li>먼저 <strong><a href="./cli-commands/">CLI 명령 참조</a></strong> 학습 —— 기본 작업 및 디버깅 도구 마스터</li><li>다음으로 <strong><a href="./troubleshooting/">문제 해결</a></strong> 학습 —— 문제 발생 시 빠르게 식별 및 해결 가능</li><li>마지막으로 <strong><a href="./performance-optimization/">성능 최적화</a></strong> 학습 —— 시스템 실행 효율 향상</li></ol></div><h2 id="하위-페이지-탐색" tabindex="-1">하위 페이지 탐색 <a class="header-anchor" href="#하위-페이지-탐색" aria-label="Permalink to &quot;하위 페이지 탐색&quot;">​</a></h2><h3 id="문제-해결" tabindex="-1"><a href="./troubleshooting/">문제 해결</a> <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;[문제 해결](./troubleshooting/)&quot;">​</a></h3><p>일반적인 문제를 해결하는 포괄적인 문제 해결 가이드, 다음을 포함:</p><ul><li>Gateway 시작 실패</li><li>채널 연결 문제(WhatsApp, Telegram, Slack 등)</li><li>인증 오류 및 권한 문제</li><li>도구 호출 실패</li><li>세션 관리 예외</li></ul><p><strong>사용 시나리오</strong>: 구체적인 문제가 발생하여 빠르게 문제 해결 및 해결이 필요한 경우.</p><hr><h3 id="cli-명령-참조" tabindex="-1"><a href="./cli-commands/">CLI 명령 참조</a> <a class="header-anchor" href="#cli-명령-참조" aria-label="Permalink to &quot;[CLI 명령 참조](./cli-commands/)&quot;">​</a></h3><p>완전한 명령 목록 및 사용법, 다음을 포함:</p><ul><li>Gateway 제어 명령(시작, 재시작, 상태)</li><li>Agent 상호 작용 명령</li><li>모델 관리 및 구성</li><li>채널 관리(로그인, 상태, 로그아웃)</li><li>세션 관리(목록, 재설정, 삭제, 압축)</li><li>노드 관리(목록, 호출, 페어링)</li><li>스킬 관리 및 구성 마법사</li></ul><p><strong>사용 시나리오</strong>: 특정 명령의 사용법 및 매개변수를 빠르게 찾거나 CLI의 완전한 기능을 학습해야 하는 경우.</p><hr><h3 id="성능-최적화" tabindex="-1"><a href="./performance-optimization/">성능 최적화</a> <a class="header-anchor" href="#성능-최적화" aria-label="Permalink to &quot;[성능 최적화](./performance-optimization/)&quot;">​</a></h3><p>Gateway 성능 및 응답 속도를 향상시키는 최적화 기술, 다음을 포함:</p><ul><li>프롬프트 캐시(Prompt Caching)로 비용 절감</li><li>세션 프루닝(Session Pruning)으로 컨텍스트 감소</li><li>동시성 제어 및 리소스 관리</li><li>메모리 최적화 및 가비지 수집</li><li>로그 수준 튜닝</li></ul><p><strong>사용 시나리오</strong>: 시스템 실행이 느리거나 리소스 사용량이 높거나 사용자 경험을 향상시키고 싶을 때.</p><h2 id="전제-조건" tabindex="-1">전제 조건 <a class="header-anchor" href="#전제-조건" aria-label="Permalink to &quot;전제 조건&quot;">​</a></h2><p>이 장절을 학습하기 전에 다음을 완료하는 것을 권장합니다:</p><ul><li>✅ <strong><a href="./../../start/getting-started/">빠른 시작</a></strong> —— 기본 설치 및 구성 프로세스 이해</li><li>✅ <strong><a href="./../../start/gateway-startup/">Gateway 시작</a></strong> —— Gateway 시작 및 관리 방법 알기</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장절을 완료한 후 다음 학습을 계속할 수 있습니다:</p><ul><li><strong><a href="./../../appendix/config-reference/">완전한 구성 참조</a></strong> —— 모든 구성 항목의 자세한 설명을 깊이 이해</li><li><strong><a href="./../../appendix/deployment/">배포 옵션</a></strong> —— 다른 플랫폼에서 Clawdbot을 배포하는 방법 학습</li><li><strong><a href="./../../appendix/development/">개발 가이드</a></strong> —— 플러그인 개발 및 기여 프로세스 이해</li></ul>',24)])])}const f=t(o,[["render",r]]);export{m as __pageData,f as default};
